String identifyLanguage(CharSequence text){
  LanguageResult result=null;
synchronized (this) {
    languageDetector.reset();
    result=languageDetector.detect(text);
  }
  if (onlyCertain && !result.isReasonablyCertain()) {
    return null;
  }
  return result.getLanguage();
}

