final static String parseLanguage(String lang){
  if (lang == null) {
    return null;
  }
  String code=null;
  String language=null;
  String langs[]=lang.split(",| |;|\\.|\\(|\\)|=",-1);
  int i=0;
  while ((language == null) && (i < langs.length)) {
    code=langs[i].split("-")[0];
    code=code.split("_")[0];
    language=(String)LANGUAGES_MAP.get(code.toLowerCase());
    i++;
  }
  return language;
}

