@Override public NutchDocument filter(NutchDocument doc,Parse parse,Text url,CrawlDatum datum,Inlinks inlinks) throws IndexingException {
  String lang=parse.getData().getParseMeta().get(Metadata.LANGUAGE);
  if (lang == null) {
    lang=parse.getData().getContentMeta().get(Response.CONTENT_LANGUAGE);
  }
  if (lang == null || lang.length() == 0) {
    lang="unknown";
  }
  if (!indexLangs.isEmpty() && !indexLangs.contains(lang)) {
    return null;
  }
  doc.add("lang",lang);
  return doc;
}

