@Test public void testLanguageIndentifier() throws IOException {
  long total=0;
  HTMLLanguageParser identifier=new HTMLLanguageParser();
  Configuration conf=new Configuration();
  conf.set("lang.extraction.policy","identify");
  identifier.setConf(conf);
  BufferedReader in=new BufferedReader(new InputStreamReader(this.getClass().getResourceAsStream("test-referencial.txt")));
  String line=null;
  while ((line=in.readLine()) != null) {
    String[] tokens=line.split(";");
    if (!tokens[0].equals("")) {
      StringBuilder content=new StringBuilder();
      BufferedReader testFile=new BufferedReader(new InputStreamReader(this.getClass().getResourceAsStream(tokens[0]),"UTF-8"));
      String testLine=null, lang=null;
      while ((testLine=testFile.readLine()) != null) {
        content.append(testLine + "\n");
        testLine=testLine.trim();
        if (testLine.length() > 256) {
          lang=identifier.identifyLanguage(testLine);
          Assert.assertEquals(tokens[1],lang);
        }
      }
      testFile.close();
      long start=System.currentTimeMillis();
      System.out.println(content.substring(0,(content.length() > 48 ? 48 : content.length())));
      lang=identifier.identifyLanguage(content);
      System.out.println(lang);
      total+=System.currentTimeMillis() - start;
      Assert.assertEquals(tokens[1],lang);
    }
  }
  in.close();
  System.out.println("Total Time=" + total);
}

