    if (lastModified + update < curTime) {
      changed=true;
      changeCnt++;
      lastModified=curTime;
    }
    LOG.info(i + ". " + changed+ "\twill fetch at "+ (p.getFetchTime() / delta)+ "\tinterval "+ (p.getFetchInterval() / SECONDS_PER_DAY)+ " days"+ "\t missed "+ miss);
    if (p.getFetchTime() <= curTime) {
