@Override public void map(Text key,CrawlDatum value,Context context) throws IOException, InterruptedException {
  if (sample < 1 && Math.random() > sample) {
    return;
  }
  if (retry != -1) {
    if (value.getRetriesSinceFetch() < retry) {
      return;
    }
  }
  if (status != null && !status.equalsIgnoreCase(CrawlDatum.getStatusName(value.getStatus())))   return;
  if (pattern != null) {
    matcher=pattern.matcher(key.toString());
    if (!matcher.matches()) {
      return;
    }
  }
  if (expr != null) {
    if (!value.execute(expr,key.toString())) {
      return;
    }
  }
  context.write(key,value);
}

