    try {
      FileSystem fs=linkDb.getFileSystem(config);
      if (!fs.exists(linkDb)) {
        conf.setBoolean(LinkDbFilter.URL_FILTERING,filter);
        conf.setBoolean(LinkDbFilter.URL_NORMALIZING,normalize);
      }
    }
 catch (    Exception e) {
      LOG.warn("LinkDb createJob:: {}",e.getMessage());
