@Override public void map(Text key,CrawlDatum value,Context context) throws IOException, InterruptedException {
  Text url=key;
  if (filter) {
    try {
      if (filters.filter(url.toString()) == null)       return;
    }
 catch (    URLFilterException e) {
      LOG.warn("Couldn't filter url: {} ({})",url,e.getMessage());
    }
  }
  CrawlDatum crawlDatum=value;
  if (!schedule.shouldFetch(url,crawlDatum,curTime)) {
    LOG.debug("-shouldFetch rejected '{}', fetchTime={}, curTime={}",url,crawlDatum.getFetchTime(),curTime);
    context.getCounter("Generator","SCHEDULE_REJECTED").increment(1);
    return;
  }
  LongWritable oldGenTime=(LongWritable)crawlDatum.getMetaData().get(Nutch.WRITABLE_GENERATE_TIME_KEY);
  if (oldGenTime != null) {
    if (oldGenTime.get() + genDelay > curTime) {
      context.getCounter("Generator","WAIT_FOR_UPDATE").increment(1);
      return;
    }
  }
  float sort=1.0f;
  try {
    sort=scfilters.generatorSortValue(key,crawlDatum,sort);
  }
 catch (  ScoringFilterException sfe) {
    if (LOG.isWarnEnabled()) {
      LOG.warn("Couldn't filter generatorSortValue for " + key + ": "+ sfe);
    }
  }
  if (expr != null) {
    if (!crawlDatum.execute(expr,key.toString())) {
      context.getCounter("Generator","EXPR_REJECTED").increment(1);
      return;
    }
  }
  if (restrictStatus != -1 && restrictStatus != crawlDatum.getStatus()) {
    context.getCounter("Generator","STATUS_REJECTED").increment(1);
    return;
  }
  if (!Float.isNaN(scoreThreshold) && sort < scoreThreshold) {
    context.getCounter("Generator","SCORE_TOO_LOW").increment(1);
    return;
  }
  if (intervalThreshold != -1 && crawlDatum.getFetchInterval() > intervalThreshold) {
    context.getCounter("Generator","INTERVAL_REJECTED").increment(1);
    return;
  }
  sortValue.set(sort);
  crawlDatum.getMetaData().put(Nutch.WRITABLE_GENERATE_TIME_KEY,genTime);
  entry.datum=crawlDatum;
  entry.url=key;
  context.write(sortValue,entry);
}

