@Override public void reduce(FloatWritable key,Iterable<SelectorEntry> values,Context context) throws IOException, InterruptedException {
  String hostname=null;
  HostDatum host=null;
  LongWritable variableFetchDelayWritable=null;
  Text variableFetchDelayKey=new Text("_variableFetchDelay_");
  int maxCount=this.maxCount;
  for (  SelectorEntry entry : values) {
    Text url=entry.url;
    String urlString=url.toString();
    URL u=null;
    if (host == null) {
      try {
        hostname=URLUtil.getHost(urlString);
        host=getHostDatum(hostname);
      }
 catch (      Exception e) {
      }
      if (host == null) {
        host=new HostDatum();
      }
 else {
        if (maxCountExpr != null) {
          long variableMaxCount=Math.round((double)maxCountExpr.execute(createContext(host)));
          LOG.info("Generator: variable maxCount: {} for {}",variableMaxCount,hostname);
          maxCount=(int)variableMaxCount;
        }
        if (fetchDelayExpr != null) {
          long variableFetchDelay=Math.round((double)fetchDelayExpr.execute(createContext(host)));
          LOG.info("Generator: variable fetchDelay: {} ms for {}",variableFetchDelay,hostname);
          variableFetchDelayWritable=new LongWritable(variableFetchDelay);
        }
      }
    }
    if (variableFetchDelayWritable != null) {
      entry.datum.getMetaData().put(variableFetchDelayKey,variableFetchDelayWritable);
    }
    if (count == limit) {
      if (currentsegmentnum < maxNumSegments) {
        count=0;
        currentsegmentnum++;
      }
 else       break;
    }
    String hostordomain=null;
    try {
      if (normalise && normalizers != null) {
        urlString=normalizers.normalize(urlString,URLNormalizers.SCOPE_GENERATE_HOST_COUNT);
      }
      u=new URL(urlString);
      if (byDomain) {
        hostordomain=URLUtil.getDomainName(u);
      }
 else {
        hostordomain=u.getHost();
      }
    }
 catch (    MalformedURLException e) {
      LOG.warn("Malformed URL: '{}', skipping ({})",urlString,StringUtils.stringifyException(e));
      context.getCounter("Generator","MALFORMED_URL").increment(1);
      continue;
    }
    hostordomain=hostordomain.toLowerCase();
    if (maxCount > 0) {
      int[] hostCount=hostCounts.get(hostordomain);
      if (hostCount == null) {
        hostCount=new int[]{1,0};
        hostCounts.put(hostordomain,hostCount);
      }
      hostCount[1]++;
      while (segCounts[hostCount[0] - 1] >= limit && hostCount[0] < maxNumSegments) {
        hostCount[0]++;
        hostCount[1]=0;
      }
      if (hostCount[1] > maxCount) {
        if (hostCount[0] < maxNumSegments) {
          hostCount[0]++;
          hostCount[1]=1;
        }
 else {
          if (hostCount[1] == (maxCount + 1)) {
            context.getCounter("Generator","HOSTS_AFFECTED_PER_HOST_OVERFLOW").increment(1);
            LOG.info("Host or domain {} has more than {} URLs for all {} segments. Additional URLs won't be included in the fetchlist.",hostordomain,maxCount,maxNumSegments);
          }
          context.getCounter("Generator","URLS_SKIPPED_PER_HOST_OVERFLOW").increment(1);
          continue;
        }
      }
      entry.segnum=new IntWritable(hostCount[0]);
      segCounts[hostCount[0] - 1]++;
    }
 else {
      entry.segnum=new IntWritable(currentsegmentnum);
      segCounts[currentsegmentnum - 1]++;
    }
    outputFile=generateFileName(entry);
    mos.write("sequenceFiles",key,entry,outputFile);
    count++;
  }
}

