    for (int i=0; i < threadCount; i++) {
      if (startDelay > 0 && i > 0) {
        Thread.sleep(startDelay);
      }
      FetcherThread t=new FetcherThread(conf,getActiveThreads(),fetchQueues,feeder,spinWaiting,lastRequestStart,innerContext,errors,segmentName,parsing,storingContent,pages,bytes);
      fetcherThreads.add(t);
      t.start();
    }
    long timeout=conf.getInt("mapreduce.task.timeout",10 * 60 * 1000) / timeoutDivisor;
    int pagesLastSec;
