    Parse p=parseResult.get(content.getUrl());
    if (p != null) {
      context.getCounter("ParserStatus",ParseStatus.majorCodes[p.getData().getStatus().getMajorCode()]).increment(1);
      return p.getData().getStatus();
    }
  }
  return null;
}

