    fiq.nextFetchTime.getAndAdd(exceptionDelay);
    LOG.info("* queue: {} >> delayed next fetch by {} ms after {} exceptions in queue",queueid,exceptionDelay,excCount);
  }
  if (fiq.getQueueSize() == 0) {
    return 0;
  }
  if (maxExceptions != -1 && excCount >= maxExceptions) {
    int deleted=fiq.emptyQueue();
    LOG.info("* queue: {} >> removed {} URLs from queue because {} exceptions occurred",queueid,deleted,excCount);
    totalSize.getAndAdd(-deleted);
    queuesMaxExceptions.add(queueid);
    return deleted;
  }
  return 0;
}

