protected String filterNormalize(String hostName){
  if (!filter && !normalize) {
    return hostName;
  }
  String url="http://" + hostName + "/";
  String normalizedUrl=url;
  try {
    if (normalize)     normalizedUrl=normalizers.normalize(url,URLNormalizers.SCOPE_DEFAULT);
    if (filter)     normalizedUrl=filters.filter(normalizedUrl);
    if (normalizedUrl == null)     return null;
  }
 catch (  Exception e) {
    return null;
  }
  if (normalizedUrl.equals(url)) {
    return hostName;
  }
  return URLUtil.getHost(url);
}

