 else {
      LOG.warn("Unrecognized type: {}",value.getClass());
    }
  }
  if (delete && fetchDatum != null) {
    if (fetchDatum.getStatus() == CrawlDatum.STATUS_FETCH_GONE || dbDatum != null && dbDatum.getStatus() == CrawlDatum.STATUS_DB_GONE) {
      context.getCounter("IndexerStatus","deleted (gone)").increment(1);
      context.write(key,DELETE_ACTION);
      return;
    }
    if (fetchDatum.getStatus() == CrawlDatum.STATUS_FETCH_REDIR_PERM || fetchDatum.getStatus() == CrawlDatum.STATUS_FETCH_REDIR_TEMP || dbDatum != null && dbDatum.getStatus() == CrawlDatum.STATUS_DB_REDIR_PERM || dbDatum != null && dbDatum.getStatus() == CrawlDatum.STATUS_DB_REDIR_TEMP) {
      context.getCounter("IndexerStatus","deleted (redirects)").increment(1);
      context.write(key,DELETE_ACTION);
      return;
    }
