 else {
      binary=new String(content.getContent());
    }
    doc.add("binaryContent",binary);
  }
  context.getCounter("IndexerStatus","indexed (add/update)").increment(1);
  NutchIndexAction action=new NutchIndexAction(doc,NutchIndexAction.ADD);
