    }
 else     if ("java.lang.Integer".equals(type)) {
      values.add(in.readInt());
    }
 else     if ("java.lang.Float".equals(type)) {
      values.add(in.readFloat());
    }
 else     if ("java.lang.Long".equals(type)) {
      values.add(in.readLong());
