protected String regexEscape(String in){
  String result=in;
  if (in != null) {
    StringBuffer sb=new StringBuffer();
    for (int i=0; i < in.length(); i++) {
      CharSequence c=in.subSequence(i,i + 1);
      if ("<([{\\^-=$!|]})?*+.>".contains(c)) {
        sb.append('\\');
      }
      sb.append(c);
    }
    result=sb.toString();
  }
  return result;
}

