public static String stripNonCharCodepoints(String input){
  StringBuilder retval=new StringBuilder();
  char ch;
  for (int i=0; i < input.length(); i++) {
    ch=input.charAt(i);
    if ((ch == 0x9 || ch == 0xa || ch == 0xd) || (ch >= 0x20 && ch <= 0xFFFD)) {
      retval.append(ch);
    }
  }
  return retval.toString();
}

