private static String normalize(final String str){
  char c;
  StringBuffer buf=new StringBuffer();
  for (int i=0; i < str.length(); i++) {
    c=str.charAt(i);
    if (Character.isLetter(c)) {
      buf.append(Character.toLowerCase(c));
    }
  }
  return buf.toString();
}

