  ProtocolOutput protocolOutput=getProtocolOutput(url,datum,this.checkRobotsTxt);
  Text turl=new Text(url);
  int numRedirects=0;
  while (protocolOutput != null && !protocolOutput.getStatus().isSuccess() && this.followRedirects && protocolOutput.getStatus().isRedirect() && maxRedirects >= numRedirects) {
    String[] stuff=protocolOutput.getStatus().getArgs();
    url=stuff[0];
