  for (  Entry<Text,Parse> entry : parseResult) {
    Text url=entry.getKey();
    Parse parse=entry.getValue();
    ParseStatus parseStatus=parse.getData().getStatus();
    context.getCounter("ParserStatus",ParseStatus.majorCodes[parseStatus.getMajorCode()]).increment(1);
    if (!parseStatus.isSuccess()) {
      LOG.warn("Error parsing: " + key + ": "+ parseStatus);
      parse=parseStatus.getEmptyParse(context.getConfiguration());
    }
    parse.getData().getContentMeta().set(Nutch.SEGMENT_NAME_KEY,context.getConfiguration().get(Nutch.SEGMENT_NAME_KEY));
    byte[] signature=SignatureFactory.getSignature(context.getConfiguration()).calculate(content,parse);
