private void appendParagraphSeparator(StringBuffer buffer){
  if (buffer.length() == 0) {
    return;
  }
  char lastChar=buffer.charAt(buffer.length() - 1);
  if ('\n' != lastChar) {
    while (lastChar == ' ') {
      buffer.deleteCharAt(buffer.length() - 1);
      lastChar=buffer.charAt(buffer.length() - 1);
    }
    if ('\n' != lastChar) {
      buffer.append('\n');
    }
  }
}

