private static String sniffCharacterEncoding(byte[] content){
  int length=content.length < CHUNK_SIZE ? content.length : CHUNK_SIZE;
  String str=new String(content,0,length,StandardCharsets.US_ASCII);
  Matcher metaMatcher=metaPattern.matcher(str);
  String encoding=null;
  if (metaMatcher.find()) {
    Matcher charsetMatcher=charsetPattern.matcher(metaMatcher.group(1));
    if (charsetMatcher.find())     encoding=charsetMatcher.group(1);
  }
  if (encoding == null) {
    metaMatcher=charsetPatternHTML5.matcher(str);
    if (metaMatcher.find()) {
      encoding=metaMatcher.group(1);
    }
  }
  if (encoding == null) {
    if (content.length >= 3 && content[0] == (byte)0xEF && content[1] == (byte)0xBB && content[2] == (byte)0xBF) {
      encoding="UTF-8";
    }
 else     if (content.length >= 2) {
      if (content[0] == (byte)0xFF && content[1] == (byte)0xFE) {
        encoding="UTF-16LE";
      }
 else       if (content[0] == (byte)0xFE && content[1] == (byte)0xFF) {
        encoding="UTF-16BE";
      }
    }
  }
  return encoding;
}

