 catch (        Exception e) {
          ;
        }
        if (url != null)         metaTags.setBaseHref(url);
      }
    }
  }
  NodeList children=node.getChildNodes();
  if (children != null) {
    int len=children.getLength();
    for (int i=0; i < len; i++) {
      getMetaTagsHelper(metaTags,children.item(i),currURL);
    }
  }
