public static String classify(String line) throws IOException {
  double prob_ir=0;
  double prob_r=0;
  String result="1";
  String[] linearray=line.replaceAll("[^a-zA-Z ]","").toLowerCase().split(" ");
  if (!ismodel) {
    Configuration configuration=new Configuration();
    FileSystem fs=FileSystem.get(configuration);
    BufferedReader bufferedReader=new BufferedReader(new InputStreamReader(fs.open(new Path("naivebayes-model"))));
    uniquewords_size=Integer.parseInt(bufferedReader.readLine());
    bufferedReader.readLine();
    numof_ir=Integer.parseInt(bufferedReader.readLine());
    numwords_ir=Integer.parseInt(bufferedReader.readLine());
    wordfreq_ir=unflattenToHashmap(bufferedReader.readLine());
    bufferedReader.readLine();
    numof_r=Integer.parseInt(bufferedReader.readLine());
    numwords_r=Integer.parseInt(bufferedReader.readLine());
    wordfreq_r=unflattenToHashmap(bufferedReader.readLine());
    ismodel=true;
    bufferedReader.close();
  }
  for (  String word : linearray) {
    if (wordfreq_ir.containsKey(word))     prob_ir+=Math.log(wordfreq_ir.get(word)) + 1 - Math.log(numwords_ir + uniquewords_size);
 else     prob_ir+=1 - Math.log(numwords_ir + uniquewords_size);
    if (wordfreq_r.containsKey(word))     prob_r+=Math.log(wordfreq_r.get(word)) + 1 - Math.log(numwords_r + uniquewords_size);
 else     prob_r+=1 - Math.log(numwords_r + uniquewords_size);
  }
  prob_ir+=Math.log(numof_ir) - Math.log(numof_ir + numof_r);
  prob_r+=Math.log(numof_r) - Math.log(numof_ir + numof_r);
  if (prob_ir > prob_r)   result="0";
 else   result="1";
  return result;
}

