    if (scheme == Scheme.HTTP) {
      port=80;
    }
 else {
      port=443;
    }
    portString="";
  }
 else {
    port=url.getPort();
    portString=":" + port;
  }
  Socket socket=null;
  try {
    socket=new Socket();
    socket.setSoTimeout(http.getTimeout());
    String sockHost=http.useProxy(url) ? http.getProxyHost() : host;
    int sockPort=http.useProxy(url) ? http.getProxyPort() : port;
