public byte[] processDeflateEncoded(byte[] compressed,URL url) throws IOException {
  if (compressed.length == 0)   return compressed;
  if (LOG.isTraceEnabled()) {
    LOG.trace("inflating....");
  }
  byte[] content;
  if (getMaxContent() >= 0) {
    content=DeflateUtils.inflateBestEffort(compressed,getMaxContent());
  }
 else {
    content=DeflateUtils.inflateBestEffort(compressed);
  }
  if (content == null)   throw new IOException("inflateBestEffort returned null");
  if (LOG.isTraceEnabled()) {
    LOG.trace("fetched " + compressed.length + " bytes of compressed content (expanded to "+ content.length+ " bytes) from "+ url);
  }
  return content;
}

