public int read() throws IOException {
  int c=in.read();
  int value=c;
  if (c != -1 && !(XMLChar.isValid(c)))   value='X';
 else   if (lastBad && c == '<') {
    in.mark(1);
    if (in.read() != '/')     value='X';
    in.reset();
  }
  lastBad=(c == 65533);
  return value;
}
public int read(char[] cbuf,int off,int len) throws IOException {
  int n=in.read(cbuf,off,len);
  if (n != -1) {
    for (int i=0; i < n; i++) {
      char c=cbuf[off + i];
      char value=c;
      if (!(XMLChar.isValid(c)))       value='X';
 else       if (lastBad && c == '<') {
        if (i != n - 1 && cbuf[off + i + 1] != '/')         value='X';
      }
      lastBad=(c == 65533);
      cbuf[off + i]=value;
    }
  }
  return n;
}

