private static final int charToNibble(char c){
  if (c >= '0' && c <= '9') {
    return c - '0';
  }
 else   if (c >= 'a' && c <= 'f') {
    return 0xa + (c - 'a');
  }
 else   if (c >= 'A' && c <= 'F') {
    return 0xA + (c - 'A');
  }
 else {
    return -1;
  }
}

